server {
    listen 80;
    server_name concertacaoamazonia.com.br;
    root /var/www/concertacaoamazonia.com.br;
    index index.php index.html;
    include /etc/nginx/snippets/security-headers.conf;

    add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
    client_max_body_size 128M;

    # ==== WP Rocket: serve cache estático sem PHP ====
    # Detecta se o visitante está logado ou tem cookie de carrinho
    set $rocket_bypass 0;
    set $rocket_bypass_reason "";

    # Bypassar para usuários logados
    if ($http_cookie ~* "wordpress_logged_in_") {
        set $rocket_bypass 1;
        set $rocket_bypass_reason "logged_in";
    }

    # Bypassar para requisições POST
    if ($request_method = POST) {
        set $rocket_bypass 1;
        set $rocket_bypass_reason "post_method";
    }

    # Bypassar para query strings (exceto as permitidas pelo WP Rocket)
    if ($query_string != "") {
        set $rocket_bypass 1;
        set $rocket_bypass_reason "query_string";
    }

    # Bypassar parâmetros aceitos pelo WP Rocket (JetEngine filters)
    if ($query_string ~* "^(eixo|jsf|jet-engine|tax)=") {
        set $rocket_bypass 0;
    }

    # Caminho do cache: /wp-content/cache/wp-rocket/{host}/{uri}/index.html
    set $rocket_cache_file "/wp-content/cache/wp-rocket/$http_host$uri/index.html";

    # Servir cache estático quando disponível e não há bypass
    location / {
        # Tenta servir: arquivo estático, cache WP Rocket, depois PHP
        try_files $uri $uri/ @rocket_cache;
    }

    location @rocket_cache {
        # Se bypass ativo, vai direto ao PHP
        if ($rocket_bypass = 1) {
            rewrite ^ /index.php last;
        }
        # Tenta o arquivo de cache, senão PHP
        try_files $rocket_cache_file /index.php?$args;
    }

    # WordPress Multisite subdirectory rewrites
    if (!-e $request_filename) {
        rewrite /wp-admin$ $scheme://$host$uri/ permanent;
        rewrite ^(/[^/]+)?(/wp-.*) $2 last;
        rewrite ^(/[^/]+)?(/.*\.php) $2 last;
    }

    # Static files caching
    location ~* \.(?:js|css|png|jpg|jpeg|gif|svg|webp|woff2?|ttf|eot)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
        try_files $uri /index.php?$args;
    }

    # Bloquear indexacao de PDFs pelo Google
    location ~* \.pdf$ {
        add_header X-Robots-Tag "noindex, nofollow" always;
        try_files $uri =404;
    }

    # Security restrictions
    location ~ /\.ht { deny all; }
    location ~* /(?:wp-config\.php|readme\.html|license\.txt)$ { deny all; }

    # ==== Hardening: rate limiting e bloqueios ====

    # wp-login.php: rate limit anti-brute-force (5 req/min, burst=3)
    location = /wp-login.php {
        limit_req zone=wp_login burst=3 nodelay;
        try_files $uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;
        fastcgi_send_timeout 60;
    }

    # xmlrpc.php: rate limit moderado — NÃO bloquear (WPML usa para sync multilíngue)
    location = /xmlrpc.php {
        limit_req zone=wp_login burst=5 nodelay;
        try_files $uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;
        fastcgi_send_timeout 60;
    }

    # wp-cron.php: bloquear acesso HTTP externo
    location = /wp-cron.php {
        allow 127.0.0.1;
        deny all;
        try_files $uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;
        fastcgi_send_timeout 60;
    }

    # wp-admin/async-upload.php: upload de arquivos grandes
    location = /wp-admin/async-upload.php {
        try_files $uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 300;
        fastcgi_send_timeout 300;
        client_max_body_size 128M;
    }

    # wp-admin: operações longas
    location ~ ^/wp-admin/ {
        try_files $uri $uri/ /index.php?$args;
        location ~ \.php$ {
            try_files $uri =404;
            include /etc/nginx/snippets/php-fpm.conf;
            fastcgi_param HTTPS on;
            fastcgi_read_timeout 120;
            fastcgi_send_timeout 120;
        }
    }

    # PHP geral
    location ~ \.php$ {
        try_files $uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;
        fastcgi_send_timeout 60;
    }
}

