ssh concertacaoamazonia.com.br-prod-sa "
python3 - << 'PYEOF'
import re

filepath = '/etc/nginx/sites-available/concertacaoamazonia.com.br'

with open(filepath, 'r') as f:
    content = f.read()

old_block = '''    # xmlrpc.php: rate limit moderado — NÃO bloquear (WPML usa para sync multilíngue)
    location = /xmlrpc.php {
        limit_req zone=wp_login burst=5 nodelay;
        try_files \$uri =404;
        include /etc/nginx/snippets/php-fpm.conf;
        fastcgi_param HTTPS on;
        fastcgi_read_timeout 60;
        fastcgi_send_timeout 60;
    }'''

new_block = '''    # xmlrpc.php: BLOQUEADO — WPML 4.8.6+ usa REST API, não xmlrpc (auditado 2026-03-31)
    # CDN fronting attack via CloudFront nodes — vetor principal do incidente
    location = /xmlrpc.php {
        access_log /var/log/nginx/blocked-xmlrpc.log combined;
        return 444;
    }'''

if old_block in content:
    content = content.replace(old_block, new_block)
