content.content:
server {
    listen 80;
    server_name concertacaoamazonia.com.br;
    root /var/www/concertacaoamazonia.com.br;
    index index.php index.html;
    include /etc/nginx/snippets/security-headers.conf;

    add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
    client_max_body_size 128M;

    # Fallback: página de manutenção quando PHP-FPM não responde
    error_page 502 503 504 /manutencao.html;
    location = /manutencao.html {
        root /var/www/concertacaoamazonia.com.br;
        internal;
        access_log off;
    }

    # ==== WP Rocket: serve cache estático sem PHP ====
    # Detecta se o visitante está logado ou tem cookie de carrinho
    set $rocket_bypass 0;
    set $rocket_bypass_reason "";

    # Bypassar para usuários logados
    if ($http_cookie ~* "wordpress_logged_in_") {
        set $rocket_bypass 1;
        set $rocket_bypass_reason "logged_in";
    }

    # Bypassar para requisições POST
    if ($request_method = POST) {
        set $rocket_bypass 1;
        set $rocket_bypass_reason "post_method";
    }

    # Bypassar para query strings (exceto as permitidas pelo WP Rocket)
    if ($query_string != "") {
        set $rocket_bypass 1;
        set $rocket_bypass_reason "query_string";
    }

    # Bypassar parâmetros aceitos pelo WP Rocket (JetEngine filters)
    if ($query_string ~* "^(eixo|jsf|jet-engine|tax)=") {
        set $rocket_bypass 0;
    }

    # Caminho do cache: /wp-content/cache/wp-rocket/{host}/{uri}/index.html
    set $rocket_cache_file "/wp-content/cache/wp-rocket/$http_host$uri/index.html";

    # Servir cache estático quando disponível e não há bypass
    location / {
        # Tenta servir: arquivo estático, cache WP Rocket, depois PHP
        try_files $uri $uri/ @rocket_cache;
    }

    location @rocket_cache {
        # Se bypass ativo, vai direto ao PHP
        if ($rocket_bypass = 1) {
            rewrite ^ /index.php last;
        }
        # Tenta o arquivo de cache, senão PHP
        try_files $rocket_cache_file /index.php?$args;
    }

    # WordPress Multisite subdirectory rewrites
    if (!-e $request_filename) {
        rewrite /wp-admin$ $scheme://$host$uri/ permanent;
        rewrite ^(/[^/]+)?(/wp-.*) $2 last;
        rewrite ^(/[^/]+)?(/.*\.php) $2 last;
    }

