cat > /tmp/fix_healthz.py << 'PYEOF'
with open('/var/www/concertacaoamazonia.com.br/healthz-deep.php', 'r') as f:
    content = f.read()

old_redis = '''// Redis: conectar via socket Unix (WP_REDIS_PATH) com AUTH
try {
    $redis_socket = null;
    $redis_pass   = null;

    if (isset($config_content)) {
        preg_match("/define.*'WP_REDIS_PATH'.*'([^']+)'/", $config_content, $sock_match);
        preg_match("/define.*'WP_REDIS_PASSWORD'.*'([^']+)'/", $config_content, $pass_match);
        if (!empty($sock_match[1])) $redis_socket = $sock_match[1];
        if (!empty($pass_match[1])) $redis_pass   = $pass_match[1];
    }

    $conn_str = $redis_socket ? "unix://{$redis_socket}" : 'tcp://127.0.0.1:6379';
    $sock = @stream_socket_client($conn_str, $errno, $errstr, 2);
    if (!$sock) throw new Exception("Cannot connect: {$errstr}");

    if ($redis_pass) {
        fwrite($sock, "*2\\r\\n\\$4\\r\\nAUTH\\r\\n\\$" . strlen($redis_pass) . "\\r\\n{$redis_pass}\\r\\n");
        $auth = fread($sock, 64);
        if (strpos($auth, '+OK') === false) throw new Exception('AUTH failed');
    }

    fwrite($sock, "*1\\r\\n\\$4\\r\\nPING\\r\\n");
    $resp = fread($sock, 64);
    fclose($sock);

    if (strpos($resp, '+PONG') !== false) {
        $checks['redis'] = 'ok';
    } else {
        throw new Exception('Unexpected: ' . trim($resp));
    }
} catch (Exception $e) {
    $checks['redis']      = 'error: ' . $e->getMessage();
    $checks['redis_note'] = 'degraded (non-fatal)';
}'''

new_redis = '''// Redis: conectar via phpredis (extensao nativa) usando WP_REDIS_PATH e WP_REDIS_PASSWORD
try {
    $redis_socket = null;
    $redis_pass   = null;

    if (isset($config_content)) {
        preg_match("/define.*'WP_REDIS_PATH'.*'([^']+)'/", $config_content, $sock_match);
        preg_match("/define.*'WP_REDIS_PASSWORD'.*'([^']+)'/", $config_content, $rpass_match);
        if (!empty($sock_match[1]))  $redis_socket = $sock_match[1];
        if (!empty($rpass_match[1])) $redis_pass   = $rpass_match[1];
    }

    if (!class_exists('Redis')) {
        throw new Exception('phpredis extension not loaded');
    }

    $r = new Redis();
    if ($redis_socket && file_exists($redis_socket)) {
        $r->connect($redis_socket, 0, 2.0);
    } else {
        $r->connect('127.0.0.1', 6379, 2.0);
    }

    if ($redis_pass) {
        $r->auth($redis_pass);
    }

    $pong = $r->ping('healthz');
    $r->close();

    if ($pong === 'healthz' || $pong === true || $pong === '+PONG') {
        $checks['redis'] = 'ok';
    } else {
        throw new Exception('Unexpected PING response: ' . var_export($pong, true));
    }
} catch (Exception $e) {
    $checks['redis']      = 'error: ' . $e->getMessage();
    $checks['redis_note'] = 'degraded (non-fatal)';
}'''

if old_redis in content:
    content = content.replace(old_redis, new_redis)
    print("Redis block replaced with phpredis native extension")
else:
    print("ERROR: old redis block not found")
    exit(1)

with open('/var/www/concertacaoamazonia.com.br/healthz-deep.php', 'w') as f:
    f.write(content)
print("File saved")
PYEOF
